// ============================================================
// NODE 1 — LOAD STATE
// Position: Right after Webhook node
// Purpose: Read persistent memory & pass context to AI Agent
// ============================================================

// Temporary: Clear polluted state
//$getWorkflowStaticData('global').conversationState = null;


const staticData = $getWorkflowStaticData('global');

// ============================================================
// STEP 1 — READ RAW WEBHOOK INPUT
// ============================================================

const rawJson         = $input.first()?.json || {};
const incomingMessage = (
  rawJson?.body?.message ||
  rawJson?.message       ||
  ''
).trim();

// ── Guard: empty message ──
if (!incomingMessage) {
  return [{
    json: {
      error: true,
      reply: "I didn't receive a message. Please type something and try again.",
      _debug: {
        rawJson,
        reason: 'incomingMessage was empty after checking both paths'
      }
    }
  }];
}

// ============================================================
// STEP 2 — SESSION EXPIRY CHECK
// THIS IS THE KEY FIX.
// Even if conversationState exists from a previous session,
// we check how old the session is. If older than 30 minutes
// of inactivity, we treat it as a brand new session and
// wipe everything — state AND cache.
// This prevents old city/price/type bleeding into new chats.
// ============================================================

const SESSION_TIMEOUT_MS = 30 * 60 * 1000; // 30 minutes
const now                = Date.now();
const lastActivity       = staticData.lastActivityAt
                             ? new Date(staticData.lastActivityAt).getTime()
                             : null;

const isSessionExpired = !lastActivity ||
                         (now - lastActivity) > SESSION_TIMEOUT_MS;

if (isSessionExpired && staticData.conversationState) {
  // Session timed out — wipe everything cleanly
  staticData.conversationState   = null;
  staticData.cache               = {};
  staticData.sessionMessageCount = 0;
  staticData.sessionStart        = null;
}

// ── Update last activity timestamp on EVERY message ──
// This is what keeps an active session alive
staticData.lastActivityAt = new Date(now).toISOString();

// ============================================================
// STEP 3 — DETECT MANUAL RESET REQUEST
// ============================================================

const RESET_TRIGGERS = ['reset', 'start over', 'new search', 'clear', 'restart'];
const isResetRequest = RESET_TRIGGERS.some(trigger =>
  incomingMessage.toLowerCase().includes(trigger)
);

if (isResetRequest) {
  staticData.conversationState   = {
    property_type: null,
    min_price:     null,
    max_price:     null,
    city:          null,
    state:         null,
    availability:  null,
    bedrooms:      null
  };
  staticData.cache               = {};
  staticData.sessionStart        = new Date().toISOString();
  staticData.sessionMessageCount = 0;
  staticData.lastActivityAt      = new Date(now).toISOString();

  return [{
    json: {
      message:             incomingMessage,
      currentState:        staticData.conversationState,
      contextSummary:      'The user has started a fresh search. No preferences collected yet.',
      sessionMessageCount: 0,
      isFirstMessage:      true,
      wasReset:            true
    }
  }];
}

// ============================================================
// STEP 4 — INITIALIZE STATE
// Runs when:
//   a) Very first message ever
//   b) Session just expired and we nulled the state above
//   c) Workflow was redeployed
// In ALL cases — cache is wiped and session resets cleanly.
// ============================================================

if (!staticData.conversationState) {
  // Wipe cache first — before anything else
  staticData.cache               = {};
  staticData.sessionMessageCount = 0;
  staticData.sessionStart        = new Date().toISOString();

  staticData.conversationState = {
    property_type: null,
    min_price:     null,
    max_price:     null,
    city:          null,
    state:         null,
    availability:  null,
    bedrooms:      null
  };
}

// ── Defensive initializations ──
if (!staticData.cache)        staticData.cache        = {};
if (!staticData.sessionStart) staticData.sessionStart = new Date().toISOString();

// ============================================================
// STEP 5 — MESSAGE COUNTERS
// ============================================================

if (!staticData.totalMessageCount)   staticData.totalMessageCount   = 0;
if (!staticData.sessionMessageCount) staticData.sessionMessageCount = 0;

staticData.totalMessageCount   += 1;
staticData.sessionMessageCount += 1;

const isFirstMessage = staticData.sessionMessageCount === 1;

// ============================================================
// STEP 6 — BUILD CONTEXT SUMMARY
// ============================================================

const s         = staticData.conversationState;
const knownInfo = [];

if (s.property_type && typeof s.property_type === 'string') {
  knownInfo.push(`property type: ${s.property_type}`);
}
if (s.city && typeof s.city === 'string') {
  knownInfo.push(`city: ${s.city}`);
}
if (s.state && typeof s.state === 'string') {
  knownInfo.push(`state/province: ${s.state}`);
}
if (s.min_price !== null && s.min_price !== undefined) {
  knownInfo.push(`minimum price: $${Number(s.min_price).toLocaleString()}`);
}
if (s.max_price !== null && s.max_price !== undefined) {
  knownInfo.push(`maximum price: $${Number(s.max_price).toLocaleString()}`);
}
if (s.bedrooms !== null && s.bedrooms !== undefined) {
  knownInfo.push(
    s.bedrooms === 0
      ? 'looking for a studio (0 bedrooms)'
      : `bedrooms: ${s.bedrooms}`
  );
}
if (s.availability === true) {
  knownInfo.push('availability: available listings only');
} else if (s.availability === false) {
  knownInfo.push('availability: all listings including unavailable');
}

const contextSummary = knownInfo.length > 0
  ? `So far the user has told us: ${knownInfo.join(', ')}.`
  : 'This is the first message — no preferences collected yet.';

// ============================================================
// STEP 7 — RETURN
// ============================================================

return [{
  json: {
    message:             incomingMessage,
    currentState:        staticData.conversationState,
    contextSummary:      contextSummary,
    sessionMessageCount: staticData.sessionMessageCount,
    totalMessageCount:   staticData.totalMessageCount,
    isFirstMessage:      isFirstMessage,
    sessionStart:        staticData.sessionStart,
    wasReset:            false,
    _debug: {
      inputPathUsed:    rawJson?.body?.message
                          ? 'json.body.message'
                          : 'json.message',
      sessionExpired:   isSessionExpired,
      lastActivityAt:   lastActivity
                          ? new Date(lastActivity).toISOString()
                          : 'never',
      idleMinutes:      lastActivity
                          ? Math.round((now - lastActivity) / 60000)
                          : null,
      knownFieldCount:  knownInfo.length,
      cacheKeys:        Object.keys(staticData.cache || {}),
      rawInputKeys:     Object.keys(rawJson)
    }
  }
}];

// ============================================================
// NODE 2 — PARSE AI + SAVE STATE
// Position: Right after AI Agent node
// Purpose: Parse AI response → validate → save to memory → route
// ============================================================

const staticData = $getWorkflowStaticData('global');
const rawAIOutput = $input.first()?.json?.text || $input.first()?.json?.output || '';

// ============================================================
// HELPER FUNCTIONS
// ============================================================

// ── Extracts JSON from AI text even if wrapped in markdown ──
function extractJSON(text) {
  if (!text || typeof text !== 'string') return null;

  // Try 1: Direct parse (AI returned clean JSON)
  try {
    return JSON.parse(text.trim());
  } catch (_) {}

  // Try 2: Extract from ```json ... ``` markdown block
  const mdMatch = text.match(/```json\s*([\s\S]*?)\s*```/i);
  if (mdMatch) {
    try { return JSON.parse(mdMatch[1].trim()); } catch (_) {}
  }

  // Try 3: Extract from ``` ... ``` (no language tag)
  const codeMatch = text.match(/```\s*([\s\S]*?)\s*```/);
  if (codeMatch) {
    try { return JSON.parse(codeMatch[1].trim()); } catch (_) {}
  }

  // Try 4: Find first { ... } block in the text
  const braceMatch = text.match(/\{[\s\S]*\}/);
  if (braceMatch) {
    try { return JSON.parse(braceMatch[0]); } catch (_) {}
  }

  // Try 5: Find last { ... } block (AI sometimes adds text after JSON)
  const allBraces = [...text.matchAll(/\{[\s\S]*?\}/g)];
  for (let i = allBraces.length - 1; i >= 0; i--) {
    try { return JSON.parse(allBraces[i][0]); } catch (_) {}
  }

  return null;
}

// ── Validates the action field ──
function validateAction(action) {
  const valid = ['DB_SEARCH', 'WEATHER_QUERY', 'RESPOND'];
  if (!action || typeof action !== 'string') return 'RESPOND';
  return valid.includes(action.toUpperCase())
    ? action.toUpperCase()
    : 'RESPOND';
}

// ── Validates and cleans a state object ──
function validateState(incoming, existing) {
  const clean = {
    property_type: null,
    min_price:     null,
    max_price:     null,
    city:          null,
    state:         null,
    availability:  null,
    bedrooms:      null
  };

  // Merge: use existing as base, overlay incoming on top
  const merged = { ...clean, ...existing, ...incoming };

  // ── property_type: must be a non-empty string ──
  if (merged.property_type && typeof merged.property_type === 'string') {
    clean.property_type = merged.property_type.trim() || null;
  }

  // ── city: must be a non-empty string ──
  if (merged.city && typeof merged.city === 'string') {
    clean.city = merged.city.trim() || null;
  }

  // ── state: must be a non-empty string ──
  if (merged.state && typeof merged.state === 'string') {
    clean.state = merged.state.trim() || null;
  }

  // ── min_price: must be a positive number ──
  if (merged.min_price !== null && merged.min_price !== undefined) {
    const val = Number(merged.min_price);
    if (!isNaN(val) && val >= 0) clean.min_price = val;
  }

  // ── max_price: must be a positive number ──
  if (merged.max_price !== null && merged.max_price !== undefined) {
    const val = Number(merged.max_price);
    if (!isNaN(val) && val >= 0) clean.max_price = val;
  }

  // ── price sanity check: min must not exceed max ──
  if (clean.min_price !== null && clean.max_price !== null) {
    if (clean.min_price > clean.max_price) {
      // Swap them silently rather than rejecting
      [clean.min_price, clean.max_price] = [clean.max_price, clean.min_price];
    }
  }

  // ── bedrooms: must be a whole non-negative number ──
  if (merged.bedrooms !== null && merged.bedrooms !== undefined) {
    const val = parseInt(merged.bedrooms, 10);
    if (!isNaN(val) && val >= 0) clean.bedrooms = val;
  }

  // ── availability: must be a boolean ──
  if (merged.availability !== null && merged.availability !== undefined) {
    if (typeof merged.availability === 'boolean') {
      clean.availability = merged.availability;
    } else if (merged.availability === 'true' || merged.availability === true) {
      clean.availability = true;
    } else if (merged.availability === 'false' || merged.availability === false) {
      clean.availability = false;
    }
  }

  return clean;
}

// ── Detects if the city changed between old and new state ──
function cityChanged(oldState, newState) {
  const oldCity = (oldState?.city || '').toLowerCase().trim();
  const newCity = (newState?.city || '').toLowerCase().trim();
  return oldCity !== newCity && newCity !== '';
}

// ── Detects if property_type changed ──
function propertyTypeChanged(oldState, newState) {
  const oldType = (oldState?.property_type || '').toLowerCase().trim();
  const newType = (newState?.property_type || '').toLowerCase().trim();
  return oldType !== newType && newType !== '';
}

// ── Invalidates cache when city or property_type changes ──
function handleCacheInvalidation(oldState, newState) {
  if (!staticData.cache) return;

  const oldKey = `${(oldState?.city || '').toLowerCase().trim()}_${(oldState?.property_type || '').toLowerCase().trim()}`;

  if (cityChanged(oldState, newState) || propertyTypeChanged(oldState, newState)) {
    if (staticData.cache[oldKey]) {
      delete staticData.cache[oldKey];
    }
  }
}

// ============================================================
// MAIN LOGIC
// ============================================================

const existingState = staticData.conversationState || {};
let aiResponse = null;
let parseError = null;

// ── Attempt to parse the AI's output ──
if (rawAIOutput) {
  aiResponse = extractJSON(rawAIOutput);
  if (!aiResponse) {
    parseError = 'Could not extract valid JSON from AI response';
  }
} else {
  parseError = 'AI returned empty output';
}

// ── If parsing completely failed, return safe fallback ──
if (!aiResponse || parseError) {
  return [{
    json: {
      action:          'RESPOND',
      updatedState:    existingState,
      friendly_message: "Sorry, I didn't quite catch that. Could you rephrase?",
      city_for_weather: null,
      missing_info:    null,
      _debug: {
        parseError,
        rawLength: rawAIOutput?.length || 0
      }
    }
  }];
}

// ── Validate action field ──
const action = validateAction(aiResponse.action);

// ── Validate and clean the updated state ──
const incomingState = aiResponse.updatedState || aiResponse.updated_state || {};
const validatedState = validateState(incomingState, existingState);

// ── Handle cache invalidation before saving new state ──
handleCacheInvalidation(existingState, validatedState);

// ── Save the clean, validated state to persistent memory ──
staticData.conversationState = validatedState;

// ── Save a log of the last action (helpful for debugging) ──
staticData.lastAction = action;
staticData.lastUpdated = new Date().toISOString();

// ── Validate weather city ──
const cityForWeather = 
  typeof aiResponse.city_for_weather === 'string' && aiResponse.city_for_weather.trim()
    ? aiResponse.city_for_weather.trim()
    : (action === 'WEATHER_QUERY' ? validatedState.city : null);

// ── Final safety check: DB_SEARCH requires property_type ──
let finalAction = action;
if (action === 'DB_SEARCH' && !validatedState.property_type) {
  finalAction = 'RESPOND';
  aiResponse.friendly_message =
    aiResponse.friendly_message ||
    "I'd love to help! Could you tell me what type of property you're looking for? For example: Apartment, Studio, or Villa.";
}

// ── Return the fully validated, clean response ──
return [{
  json: {
    action:           finalAction,
    updatedState:     validatedState,
    friendly_message: aiResponse.friendly_message || aiResponse.message || null,
    city_for_weather: cityForWeather,
    missing_info:     aiResponse.missing_info || null,
    _debug: {
      originalAction:  action,
      finalAction:     finalAction,
      parseSuccess:    true,
      stateChanged:    JSON.stringify(existingState) !== JSON.stringify(validatedState),
      cityChanged:     cityChanged(existingState, validatedState),
      typeChanged:     propertyTypeChanged(existingState, validatedState),
      timestamp:       staticData.lastUpdated
    }
  }
}];

// ============================================================
// NODE 3 — CHECK CACHE
// Position: After "Parse AI + Save State", Before Switch node
// Purpose: Check if we already have results for this 
//          city + property_type combo → skip DB if we do
// ============================================================

const staticData = $getWorkflowStaticData('global');
const input = $input.first()?.json;

// ============================================================
// HELPER FUNCTIONS
// ============================================================

// ── Builds a normalized, consistent cache key ──
function buildCacheKey(city, propertyType) {
  const safeCity = (city || '').toLowerCase().trim().replace(/\s+/g, '_');
  const safeType = (propertyType || '').toLowerCase().trim().replace(/\s+/g, '_');

  // Both must exist for a valid key
  if (!safeCity || !safeType) return null;

  return `${safeCity}__${safeType}`;
}

// ── Checks if a cache entry is still fresh (under 30 mins) ──
function isCacheFresh(cacheEntry) {
  if (!cacheEntry || !cacheEntry.cachedAt) return false;

  const CACHE_TTL_MS = 30 * 60 * 1000; // 30 minutes
  const age = Date.now() - new Date(cacheEntry.cachedAt).getTime();
  return age < CACHE_TTL_MS;
}

// ── Applies price + bedroom filters on cached results ──
function applyFilters(results, state) {
  if (!Array.isArray(results)) return [];

  let filtered = [...results];

  // Price filters
  if (state.min_price !== null && state.min_price !== undefined) {
    filtered = filtered.filter(p => Number(p.price) >= Number(state.min_price));
  }
  if (state.max_price !== null && state.max_price !== undefined) {
    filtered = filtered.filter(p => Number(p.price) <= Number(state.max_price));
  }

  // Bedroom filter
  if (state.bedrooms !== null && state.bedrooms !== undefined) {
    filtered = filtered.filter(p => Number(p.bedrooms) === Number(state.bedrooms));
  }

  // Availability filter
  if (state.availability !== null && state.availability !== undefined) {
    filtered = filtered.filter(p => p.availability === state.availability);
  }

  return filtered;
}

// ── Summarises what filters are active (for debug) ──
function describeFilters(state) {
  const active = [];
  if (state.min_price) active.push(`min $${state.min_price}`);
  if (state.max_price) active.push(`max $${state.max_price}`);
  if (state.bedrooms)  active.push(`${state.bedrooms} beds`);
  if (state.availability !== null) active.push(`available: ${state.availability}`);
  return active.length > 0 ? active.join(', ') : 'none';
}

// ============================================================
// GUARD: If action is not DB_SEARCH, pass straight through
// ============================================================

// This node only makes sense for DB_SEARCH actions.
// WEATHER_QUERY and RESPOND should never reach here,
// but if they do (mis-wiring), pass them through safely.
if (!input) {
  return [{
    json: {
      action: 'RESPOND',
      updatedState: staticData.conversationState || {},
      friendly_message: 'Something went wrong reading your request. Please try again.',
      fromCache: false,
      cacheKey: null,
      results: null,
      _debug: { error: 'No input received in Check Cache node' }
    }
  }];
}

const action      = input.action;
const state       = input.updatedState || staticData.conversationState || {};
const friendlyMsg = input.friendly_message;
const missingInfo = input.missing_info;

// Pass non-DB_SEARCH actions straight through untouched
if (action !== 'DB_SEARCH') {
  return [{
    json: {
      ...input,
      fromCache: false,
      cacheKey: null,
      results: null,
      _debug: {
        skippedCache: true,
        reason: `Action is ${action}, cache only applies to DB_SEARCH`
      }
    }
  }];
}

// ============================================================
// GUARD: property_type is mandatory before any cache/DB check
// ============================================================

if (!state.property_type) {
  return [{
    json: {
      action: 'RESPOND',
      updatedState: state,
      friendly_message: friendlyMsg ||
        "What type of property are you looking for? For example: Apartment, Studio, or Villa.",
      fromCache: false,
      cacheKey: null,
      results: null,
      _debug: {
        blockedReason: 'property_type missing — cannot build cache key or query DB'
      }
    }
  }];
}

// ============================================================
// BUILD CACHE KEY
// ============================================================

const cacheKey = buildCacheKey(state.city, state.property_type);

// If city is missing we can't build a key — let DB handle it
if (!cacheKey) {
  return [{
    json: {
      action:           'DB_SEARCH',
      updatedState:     state,
      friendly_message: friendlyMsg,
      missing_info:     missingInfo,
      fromCache:        false,
      cacheKey:         null,
      results:          null,
      _debug: {
        cacheMiss: true,
        reason: 'Could not build cache key — city may be missing',
        city: state.city,
        property_type: state.property_type
      }
    }
  }];
}

// ============================================================
// CACHE LOOKUP
// ============================================================

const cache      = staticData.cache || {};
const cacheEntry = cache[cacheKey];

// ── CACHE HIT ──
if (cacheEntry && isCacheFresh(cacheEntry)) {
  const allCachedResults = cacheEntry.results || [];

  // Re-apply filters on cached results
  // (user may have changed price/bedrooms since last fetch)
  const filteredResults = applyFilters(allCachedResults, state);
  const top3            = filteredResults.slice(0, 3);

  return [{
    json: {
      action:           'DB_SEARCH',
      updatedState:     state,
      friendly_message: friendlyMsg,
      missing_info:     missingInfo,
      fromCache:        true,
      cacheKey:         cacheKey,
      results:          top3,
      _debug: {
        cacheHit:           true,
        cacheKey:           cacheKey,
        cachedAt:           cacheEntry.cachedAt,
        totalCachedResults: allCachedResults.length,
        afterFilters:       filteredResults.length,
        returning:          top3.length,
        filtersApplied:     describeFilters(state),
        ageSeconds:         Math.round(
          (Date.now() - new Date(cacheEntry.cachedAt).getTime()) / 1000
        )
      }
    }
  }];
}

// ── CACHE MISS (expired or never cached) ──
const missReason = cacheEntry && !isCacheFresh(cacheEntry)
  ? 'Cache expired (older than 30 minutes)'
  : 'No cache entry found for this city + property type';

// Clean up stale entry if it exists
if (cacheEntry) {
  delete staticData.cache[cacheKey];
}

return [{
  json: {
    action:           'DB_SEARCH',
    updatedState:     state,
    friendly_message: friendlyMsg,
    missing_info:     missingInfo,
    fromCache:        false,
    cacheKey:         cacheKey,
    results:          null,
    _debug: {
      cacheMiss:  true,
      cacheKey:   cacheKey,
      missReason: missReason
    }
  }
}];

// ============================================================
// NODE 4 — SAVE CACHE + TOP 3
// Position: Right after Supabase "Get Many Rows" node
// Purpose: Save ALL raw results to cache → apply all filters
//          → sort → return top 3 to Format Response
// ============================================================

const staticData = $getWorkflowStaticData('global');

// ============================================================
// STEP 1 — COLLECT ALL SUPABASE ROWS
// Supabase returns each row as a separate n8n item.
// $input.all() collects every item into one array.
// ============================================================

const allItems = $input.all();

// Guard: if Supabase returned nothing at all (not even empty)
if (!allItems || allItems.length === 0) {
  const fallbackState = staticData.conversationState || {};
  return [{
    json: {
      results:      [],
      state:        fallbackState,
      fromCache:    false,
      totalFetched: 0,
      _debug: {
        error: 'Supabase returned no items — possible connection issue',
        cacheKey: buildCacheKey(fallbackState.city, fallbackState.property_type)
      }
    }
  }];
}

// Extract raw JSON data from each n8n item
const rawResults = allItems.map(item => item.json).filter(Boolean);

// ============================================================
// STEP 2 — READ STATE FROM PREVIOUS NODE
// The state was passed through by Node 3 (Check Cache)
// inside the first item's json.updatedState
// ============================================================

const firstItem   = allItems[0]?.json || {};
const state       = firstItem.updatedState
                 || firstItem.state
                 || staticData.conversationState
                 || {};
const cacheKey    = firstItem.cacheKey || buildCacheKey(state.city, state.property_type);
const friendlyMsg = firstItem.friendly_message || null;
const missingInfo = firstItem.missing_info     || null;

// ============================================================
// HELPER FUNCTIONS
// ============================================================

// ── Builds normalized composite cache key ──
function buildCacheKey(city, propertyType) {
  const safeCity = (city || '').toLowerCase().trim().replace(/\s+/g, '_');
  const safeType = (propertyType || '').toLowerCase().trim().replace(/\s+/g, '_');
  if (!safeCity || !safeType) return null;
  return `${safeCity}__${safeType}`;
}

// ── Cleans and normalizes a single property row from Supabase ──
function normalizeProperty(row) {
  if (!row || typeof row !== 'object') return null;

  return {
    id:            row.id            || null,
    property_type: row.property_type || null,
    price:         row.price !== undefined && row.price !== null
                     ? Number(row.price)
                     : null,
    city:          row.city          || null,
    state:         row.state         || null,
    availability:  typeof row.availability === 'boolean'
                     ? row.availability
                     : row.availability === 'true'
                       ? true
                       : row.availability === 'false'
                         ? false
                         : null,
    bedrooms:      row.bedrooms !== undefined && row.bedrooms !== null
                     ? parseInt(row.bedrooms, 10)
                     : null,
    amenities:     Array.isArray(row.amenities)
                     ? row.amenities
                     : typeof row.amenities === 'string'
                       ? row.amenities.replace(/[{}"]/g, '').split(',').map(a => a.trim()).filter(Boolean)
                       : []
  };
}

// ── Applies ALL active filters from state ──
function applyFilters(results, state) {
  let filtered = [...results];
  const log    = [];

  // Filter 1: property_type (exact match, case-insensitive)
  if (state.property_type) {
    const type = state.property_type.toLowerCase().trim();
    filtered   = filtered.filter(p =>
      (p.property_type || '').toLowerCase().trim() === type
    );
    log.push(`property_type="${state.property_type}" → ${filtered.length} left`);
  }

  // Filter 2: city (case-insensitive)
  if (state.city) {
    const city = state.city.toLowerCase().trim();
    filtered   = filtered.filter(p =>
      (p.city || '').toLowerCase().trim() === city
    );
    log.push(`city="${state.city}" → ${filtered.length} left`);
  }

  // Filter 3: min_price
  if (state.min_price !== null && state.min_price !== undefined) {
    const min = Number(state.min_price);
    filtered  = filtered.filter(p =>
      p.price !== null && Number(p.price) >= min
    );
    log.push(`min_price=$${min} → ${filtered.length} left`);
  }

  // Filter 4: max_price
  if (state.max_price !== null && state.max_price !== undefined) {
    const max = Number(state.max_price);
    filtered  = filtered.filter(p =>
      p.price !== null && Number(p.price) <= max
    );
    log.push(`max_price=$${max} → ${filtered.length} left`);
  }

  // Filter 5: bedrooms (exact match)
  if (state.bedrooms !== null && state.bedrooms !== undefined) {
    const beds = parseInt(state.bedrooms, 10);
    filtered   = filtered.filter(p =>
      p.bedrooms !== null && parseInt(p.bedrooms, 10) === beds
    );
    log.push(`bedrooms=${beds} → ${filtered.length} left`);
  }

  // Filter 6: availability
  if (state.availability !== null && state.availability !== undefined) {
    filtered = filtered.filter(p => p.availability === state.availability);
    log.push(`availability=${state.availability} → ${filtered.length} left`);
  }

  return { filtered, log };
}

// ── Sorts results: available first, then by price ascending ──
function sortResults(results) {
  return [...results].sort((a, b) => {
    // Available properties first
    if (a.availability === true && b.availability !== true) return -1;
    if (b.availability === true && a.availability !== true) return  1;

    // Then sort by price ascending (cheapest first)
    const priceA = a.price ?? Infinity;
    const priceB = b.price ?? Infinity;
    return priceA - priceB;
  });
}

// ============================================================
// STEP 3 — NORMALIZE ALL RAW ROWS FROM SUPABASE
// Clean every row: fix types, handle nulls, parse amenities
// ============================================================

const normalizedResults = rawResults
  .map(normalizeProperty)
  .filter(Boolean); // Remove any rows that failed normalization

// ============================================================
// STEP 4 — SAVE ALL NORMALIZED RESULTS TO CACHE
// Save BEFORE filtering so future price/bedroom changes
// can re-filter the full set without hitting DB again.
// ============================================================

if (!staticData.cache) staticData.cache = {};

if (cacheKey) {
  staticData.cache[cacheKey] = {
    results:  normalizedResults,   // Full unfiltered set
    cachedAt: new Date().toISOString(),
    city:     state.city,
    type:     state.property_type,
    count:    normalizedResults.length
  };
}

// ============================================================
// STEP 5 — APPLY FILTERS
// Now filter the full set down to matching results
// ============================================================

const { filtered, log: filterLog } = applyFilters(normalizedResults, state);

// ============================================================
// STEP 6 — SORT
// Available first → then cheapest first
// ============================================================

const sorted = sortResults(filtered);

// ============================================================
// STEP 7 — SLICE TOP 3
// ============================================================

const top3 = sorted.slice(0, 3);

// ============================================================
// STEP 8 — RETURN
// ============================================================

return [{
  json: {
    results:          top3,
    state:            state,
    fromCache:        false,
    friendly_message: friendlyMsg,
    missing_info:     missingInfo,
    _debug: {
      totalFetchedFromDB:  rawResults.length,
      afterNormalization:  normalizedResults.length,
      afterFilters:        filtered.length,
      returning:           top3.length,
      filterSteps:         filterLog,
      cacheKey:            cacheKey,
      cachedAt:            staticData.cache[cacheKey]?.cachedAt || null,
      sortOrder:           'available first, then price ascending',
      filtersActive: {
        property_type: state.property_type || null,
        city:          state.city          || null,
        min_price:     state.min_price     || null,
        max_price:     state.max_price     || null,
        bedrooms:      state.bedrooms      || null,
        availability:  state.availability  ?? null
      }
    }
  }
}];

// ============================================================
// NODE 6 — FORMAT RESPONSE
// Position: Last node before "Respond to Webhook"
// Purpose: All three branches merge here → detect which
//          branch arrived → format into one clean reply
// ============================================================

const staticData = $getWorkflowStaticData('global');
const input      = $input.first()?.json;

// ============================================================
// HELPER FUNCTIONS
// ============================================================

function safeStr(value, fallback = '') {
  if (value === null || value === undefined) return fallback;
  const str = String(value).trim();
  return str.length > 0 ? str : fallback;
}

function formatPrice(price) {
  const num = Number(price);
  if (isNaN(num) || num <= 0) return 'Price not listed';
  return '$' + num.toLocaleString('en-US');
}

function formatBedrooms(bedrooms) {
  const n = parseInt(bedrooms, 10);
  if (isNaN(n) || n < 0) return null;
  if (n === 0) return 'Studio';
  if (n === 1) return '1 bed';
  return `${n} beds`;
}

function formatAmenities(amenities) {
  if (!Array.isArray(amenities) || amenities.length === 0) {
    return 'No amenities listed';
  }
  return amenities
    .filter(Boolean)
    .map(a => String(a).trim())
    .join(' · ');
}

function formatAvailability(availability) {
  if (availability === true)  return 'Available now';
  if (availability === false) return 'Not available';
  return null;
}

// ── Validates a property row is real and not a ghost row ──
// Supabase can return empty/null rows. A valid result needs
// at least 2 of these 3 core fields to be considered real.
function isValidResult(property) {
  if (!property || typeof property !== 'object') return false;

  const hasType  = property.property_type &&
                   typeof property.property_type === 'string' &&
                   property.property_type.trim().length > 0;

  const hasPrice = property.price !== null     &&
                   property.price !== undefined &&
                   Number(property.price) > 0;

  const hasCity  = property.city &&
                   typeof property.city === 'string' &&
                   property.city.trim().length > 0;

  const validFieldCount = [hasType, hasPrice, hasCity]
    .filter(Boolean).length;

  return validFieldCount >= 2;
}

function formatPropertyCard(property, index) {
  if (!property || typeof property !== 'object') return null;

  const num          = index + 1;
  const type         = safeStr(property.property_type, 'Property');
  const price        = formatPrice(property.price);
  const city         = safeStr(property.city, '');
  const stateName    = safeStr(property.state, '');
  const location     = [city, stateName].filter(Boolean).join(', ');
  const beds         = formatBedrooms(property.bedrooms);
  const amenities    = formatAmenities(property.amenities);
  const availability = formatAvailability(property.availability);

  let card = `${num}. ${type} — ${price}/mo\n`;
  if (location)     card += `   📍 ${location}\n`;

  const details = [beds, availability].filter(Boolean);
  if (details.length > 0) card += `   ${details.join(' · ')}\n`;

  card += `   Amenities: ${amenities}\n`;
  return card;
}

function buildIntroLine(count, state, fromCache) {
  const type  = safeStr(state?.property_type, 'properties');
  const city  = safeStr(state?.city, '');
  const cache = fromCache ? ' ⚡' : '';

  if (count === 1) {
    return city
      ? `I found 1 ${type} in ${city} that matches your criteria${cache}:`
      : `I found 1 ${type} that matches your criteria${cache}:`;
  }
  return city
    ? `Great news! Here are ${count} ${type}s in ${city} that match your criteria${cache}:`
    : `Great news! Here are ${count} ${type}s that match your criteria${cache}:`;
}

function buildSearchSummary(state) {
  const parts = [];
  if (state?.min_price && state?.max_price) {
    parts.push(`budget $${Number(state.min_price).toLocaleString()}–$${Number(state.max_price).toLocaleString()}`);
  } else if (state?.min_price) {
    parts.push(`min $${Number(state.min_price).toLocaleString()}`);
  } else if (state?.max_price) {
    parts.push(`max $${Number(state.max_price).toLocaleString()}`);
  }
  if (state?.bedrooms)           parts.push(formatBedrooms(state.bedrooms));
  if (state?.availability === true)  parts.push('available now');
  if (state?.availability === false) parts.push('all listings');

  return parts.length > 0
    ? `Search filters: ${parts.join(', ')}`
    : null;
}

function buildNoResultsMessage(state) {
  const type = safeStr(state?.property_type, 'properties');
  const city = safeStr(state?.city, '');

  let msg = city
    ? `I couldn't find any ${type}s in ${city} matching your criteria.`
    : `I couldn't find any ${type}s matching your criteria.`;

  const suggestions = [];
  if (state?.min_price || state?.max_price) suggestions.push('adjusting your budget');
  if (state?.bedrooms)                      suggestions.push('changing the number of bedrooms');
  if (state?.city)                          suggestions.push('searching in a nearby city');

  if (suggestions.length > 0) {
    msg += ` You could try ${suggestions.join(' or ')}.`;
  }

  msg += '\nWhat would you like to change?';
  return msg;
}

function buildMissingInfoPrompt(missingInfo, state) {
  if (missingInfo && typeof missingInfo === 'string' && missingInfo.trim()) {
    return `\n\n${missingInfo.trim()}`;
  }
  if (!state?.property_type) {
    return '\n\nWhat type of property are you looking for? (Apartment, Studio, Villa, etc.)';
  }
  if (!state?.city) {
    return '\n\nWhich city would you like to search in?';
  }
  return '';
}

// ============================================================
// GUARD: Handle completely missing input
// ============================================================

if (!input) {
  return [{
    json: {
      reply: "Something went wrong on my end. Could you send your message again?",
      _debug: { error: 'No input received in Format Response node' }
    }
  }];
}

// ============================================================
// BRANCH DETECTION — FIXED PRIORITY ORDER
// ============================================================

const rawResults   = Array.isArray(input.results) ? input.results : [];

// ── Filter out ghost/empty rows from Supabase ──
const validResults = rawResults.filter(isValidResult);

const hasValidResults = validResults.length > 0;
const hasDirectReply  = typeof input.reply === 'string' &&
                        input.reply.trim().length > 0;
const hasFriendly     = typeof input.friendly_message === 'string' &&
                        input.friendly_message.trim().length > 0;
const hasMissingInfo  = typeof input.missing_info === 'string' &&
                        input.missing_info.trim().length > 0;

const state       = input.updatedState ||
                    input.state        ||
                    staticData.conversationState || {};
const fromCache   = input.fromCache === true;
const missingInfo = input.missing_info || null;

// ── Key guard: if state is empty, AI is still collecting
//    info — never show DB results with null state ──
const stateIsEmpty   = !state.property_type && !state.city;
const aiNeedsMoreInfo = stateIsEmpty || hasMissingInfo;

let finalReply = '';
let branchUsed = '';

// ============================================================
// BRANCH 1 — AI NEEDS MORE INFO (highest priority)
// Fires when: state is empty OR missing_info is set
// This MUST come before DB_SEARCH check so that a ghost
// result row never overrides the AI's clarifying question.
// ============================================================

if (aiNeedsMoreInfo && hasFriendly) {
  branchUsed = 'PLAIN_CHAT_PRIORITY';
  finalReply = input.friendly_message.trim();
  finalReply += buildMissingInfoPrompt(missingInfo, state);
}

// ============================================================
// BRANCH 2 — DB SEARCH RESULTS (valid results only)
// Fires when: valid results exist AND state has property_type
// ============================================================

else if (hasValidResults && state.property_type) {
  branchUsed = 'DB_SEARCH';

  const intro   = buildIntroLine(validResults.length, state, fromCache);
  finalReply    = intro ? intro + '\n\n' : '';

  const summary = buildSearchSummary(state);
  if (summary) finalReply += `${summary}\n\n`;

  const cards = validResults
    .map((property, index) => formatPropertyCard(property, index))
    .filter(Boolean);

  finalReply += cards.join('\n');

  if (validResults.length === 3) {
    finalReply += '\nWant me to refine these results? '
      + 'You can adjust the budget, bedrooms, or city.';
  } else {
    finalReply += `\nThese are all the ${state?.property_type || 'properties'} `
      + 'I found matching your criteria. '
      + 'Want to broaden the search?';
  }
}

// ============================================================
// BRANCH 3 — NO VALID RESULTS (ran DB but got nothing real)
// Fires when: results array exists but all rows are invalid
// ============================================================

else if (input.results !== undefined && !hasValidResults && state.property_type) {
  branchUsed = 'NO_RESULTS';
  finalReply = buildNoResultsMessage(state);
}

// ============================================================
// BRANCH 4 — WEATHER REPLY
// Fires when: reply string set by Node 5
// ============================================================

else if (hasDirectReply) {
  branchUsed = 'WEATHER';
  finalReply = input.reply;
  finalReply += buildMissingInfoPrompt(missingInfo, state);
}

// ============================================================
// BRANCH 5 — PLAIN CHAT / AI RESPONSE
// Fires when: friendly_message from AI
// ============================================================

else if (hasFriendly) {
  branchUsed = 'PLAIN_CHAT';
  finalReply = input.friendly_message.trim();
  finalReply += buildMissingInfoPrompt(missingInfo, state);
}

// ============================================================
// BRANCH 6 — ABSOLUTE FALLBACK
// ============================================================

else {
  branchUsed = 'FALLBACK';
  const type = safeStr(state?.property_type, '');
  const city = safeStr(state?.city, '');

  if (type && city) {
    finalReply = `I'm ready to search for ${type}s in ${city}. Would you like me to go ahead?`;
  } else if (type) {
    finalReply = `I'm looking for ${type}s for you. Which city should I search in?`;
  } else {
    finalReply = "I'm here to help you find the perfect property. "
      + "What type of property are you looking for? "
      + "(Apartment, Studio, Villa, etc.)";
  }
}

// ============================================================
// FINAL SAFETY NET
// ============================================================

if (!finalReply || !finalReply.trim()) {
  finalReply = "I'm here to help you find a property. What are you looking for?";
}

// ============================================================
// RETURN
// ============================================================

return [{
  json: {
    reply: finalReply.trim(),
    _debug: {
      branchUsed,
      fromCache,
      rawResultCount:   rawResults.length,
      validResultCount: validResults.length,
      ghostRowsDropped: rawResults.length - validResults.length,
      hasValidResults,
      hasDirectReply,
      hasFriendly,
      hasMissingInfo,
      stateIsEmpty,
      aiNeedsMoreInfo,
      stateSnapshot: {
        property_type: state?.property_type || null,
        city:          state?.city          || null,
        min_price:     state?.min_price     || null,
        max_price:     state?.max_price     || null,
        bedrooms:      state?.bedrooms      || null,
        availability:  state?.availability  ?? null
      },
      replyLength: finalReply.trim().length,
      timestamp:   new Date().toISOString()
    }
  }
}];

// ============================================================
// NODE 5 — WEATHER FORMATTER
// Position: Right after OpenWeather HTTP Request node
// Purpose: Extract only useful fields from the huge
//          OpenWeather API response → build one friendly
//          sentence → pass to Format Response node
// ============================================================

const staticData = $getWorkflowStaticData('global');
const weatherRaw = $input.first()?.json;

// ============================================================
// HELPER FUNCTIONS
// ============================================================

// ── Safely rounds a number, returns null if invalid ──
function safeRound(value) {
  const num = Number(value);
  return isNaN(num) ? null : Math.round(num);
}

// ── Converts wind speed (m/s) to a human label ──
function windLabel(speedMs) {
  const s = Number(speedMs);
  if (isNaN(s))  return 'unknown winds';
  if (s < 0.5)   return 'calm';
  if (s < 3.3)   return 'light breeze';
  if (s < 7.9)   return 'moderate breeze';
  if (s < 13.8)  return 'fresh breeze';
  if (s < 20.7)  return 'strong winds';
  if (s < 28.4)  return 'near gale';
  return 'storm-level winds';
}

// ── Converts humidity % to a human label ──
function humidityLabel(pct) {
  const h = Number(pct);
  if (isNaN(h)) return '';
  if (h < 30)   return 'very dry';
  if (h < 50)   return 'comfortable';
  if (h < 70)   return 'moderate humidity';
  if (h < 85)   return 'humid';
  return 'very humid';
}

// ── Converts visibility (metres) to a readable string ──
function visibilityLabel(metres) {
  if (metres === undefined || metres === null) return null;
  const m = Number(metres);
  if (isNaN(m)) return null;
  if (m >= 10000) return 'excellent visibility';
  if (m >= 5000)  return 'good visibility';
  if (m >= 1000)  return 'moderate visibility';
  return 'poor visibility';
}

// ── Converts Unix timestamp + timezone offset → local time ──
function toLocalTime(unixSeconds, timezoneOffsetSeconds) {
  if (!unixSeconds) return null;
  const utcMs      = unixSeconds * 1000;
  const offsetMs   = (timezoneOffsetSeconds || 0) * 1000;
  const localDate  = new Date(utcMs + offsetMs);

  const hours   = localDate.getUTCHours();
  const minutes = String(localDate.getUTCMinutes()).padStart(2, '0');
  const ampm    = hours >= 12 ? 'PM' : 'AM';
  const h12     = hours % 12 || 12;
  return `${h12}:${minutes} ${ampm}`;
}

// ── Capitalises first letter of a string ──
function capitalise(str) {
  if (!str || typeof str !== 'string') return '';
  return str.charAt(0).toUpperCase() + str.slice(1);
}

// ── Picks a relevant emoji based on weather condition code ──
function weatherEmoji(conditionCode, isDay) {
  if (!conditionCode) return '';
  const code = Number(conditionCode);

  if (code >= 200 && code < 300) return 'stormy';
  if (code >= 300 && code < 400) return 'drizzling';
  if (code >= 500 && code < 600) return 'rainy';
  if (code >= 600 && code < 700) return 'snowy';
  if (code >= 700 && code < 800) return 'foggy';
  if (code === 800) return isDay ? 'sunny' : 'clear night';
  if (code === 801 || code === 802) return 'partly cloudy';
  if (code >= 803) return 'overcast';
  return '';
}

// ── Builds a clothing/activity suggestion based on conditions ──
function buildSuggestion(tempC, conditionCode, windSpeedMs) {
  const temp = Number(tempC);
  const code = Number(conditionCode);
  const wind = Number(windSpeedMs);
  const tips = [];

  if (isNaN(temp)) return null;

  // Temperature tips
  if (temp <= 0)        tips.push("it's freezing — heavy coat and gloves essential");
  else if (temp <= 10)  tips.push("quite cold — a warm coat is recommended");
  else if (temp <= 18)  tips.push("cool weather — a light jacket is a good idea");
  else if (temp <= 25)  tips.push("pleasant temperature for house viewings");
  else if (temp <= 32)  tips.push("warm day — light clothing recommended");
  else                  tips.push("very hot — stay hydrated during property visits");

  // Rain tips
  if (code >= 200 && code < 700) tips.push("bring an umbrella");

  // Wind tips
  if (!isNaN(wind) && wind >= 13.8) tips.push("expect strong winds");

  return tips.join(', ');
}

// ============================================================
// GUARD: Handle missing or failed API response
// ============================================================

if (!weatherRaw) {
  const state = staticData.conversationState || {};
  return [{
    json: {
      action:           'RESPOND',
      updatedState:     state,
      reply:            "I wasn't able to fetch the weather right now. " +
                        "Would you like to continue your property search instead?",
      _debug: { error: 'No weather data received — HTTP node may have failed' }
    }
  }];
}

// OpenWeather returns an error object with a "cod" field
// e.g. { cod: '404', message: 'city not found' }
if (weatherRaw.cod && String(weatherRaw.cod) !== '200') {
  const state      = staticData.conversationState || {};
  const errMessage = weatherRaw.message || 'Unknown error';
  const cityTried  = state.city || 'that location';

  return [{
    json: {
      action:       'RESPOND',
      updatedState: state,
      reply:        `I couldn't find weather data for ${cityTried}. ` +
                    `The API said: "${errMessage}". ` +
                    `Want me to try a different city, or continue your property search?`,
      _debug: {
        apiError:  errMessage,
        apiCode:   weatherRaw.cod,
        cityTried: cityTried
      }
    }
  }];
}

// ============================================================
// STEP 1 — EXTRACT ALL USEFUL FIELDS
// ============================================================

// Core identifiers
const cityName    = weatherRaw.name                        || 'Unknown City';
const countryCode = weatherRaw.sys?.country               || '';
const timezoneOffset = weatherRaw.timezone                 || 0;

// Temperature block
const tempC       = safeRound(weatherRaw.main?.temp);
const feelsLikeC  = safeRound(weatherRaw.main?.feels_like);
const tempMinC    = safeRound(weatherRaw.main?.temp_min);
const tempMaxC    = safeRound(weatherRaw.main?.temp_max);

// Condition block (weather is an array — take primary condition)
const conditions     = Array.isArray(weatherRaw.weather) ? weatherRaw.weather : [];
const primaryCond    = conditions[0] || {};
const conditionCode  = primaryCond.id          || null;
const conditionMain  = primaryCond.main         || 'Unknown';
const conditionDesc  = primaryCond.description  || 'no description available';

// Atmosphere block
const humidity    = weatherRaw.main?.humidity    ?? null;
const pressure    = weatherRaw.main?.pressure    ?? null;
const visibility  = weatherRaw.visibility        ?? null;
const cloudPct    = weatherRaw.clouds?.all       ?? null;

// Wind block
const windSpeed   = weatherRaw.wind?.speed       ?? null;
const windDeg     = weatherRaw.wind?.deg         ?? null;
const windGust    = weatherRaw.wind?.gust        ?? null;

// Sun times
const sunriseTime = toLocalTime(weatherRaw.sys?.sunrise, timezoneOffset);
const sunsetTime  = toLocalTime(weatherRaw.sys?.sunset,  timezoneOffset);

// Determine day or night from condition icon
const isDay = primaryCond.icon
  ? !primaryCond.icon.endsWith('n')
  : true;

// ============================================================
// STEP 2 — BUILD HUMAN LABELS FROM RAW VALUES
// ============================================================

const weatherType  = weatherEmoji(conditionCode, isDay);
const windDesc     = windLabel(windSpeed);
const humidityDesc = humidityLabel(humidity);
const visibilityDesc = visibilityLabel(visibility);
const suggestion   = buildSuggestion(tempC, conditionCode, windSpeed);

// ============================================================
// STEP 3 — READ CONVERSATION STATE
// We use this to keep property search context alive
// even while the user is asking about weather
// ============================================================

const convState     = staticData.conversationState || {};
const propertyType  = convState.property_type || null;
const searchCity    = convState.city          || null;

// ============================================================
// STEP 4 — BUILD THE REPLY SENTENCE
// Core: temp + feels like + condition + wind + humidity
// Tail: property search context bridge
// ============================================================

// ── Core weather line ──
let weatherLine = `The weather in ${cityName}`;
if (countryCode) weatherLine += `, ${countryCode}`;
weatherLine += ` right now`;

if (tempC !== null) {
  weatherLine += ` is ${tempC}°C`;
  if (feelsLikeC !== null && feelsLikeC !== tempC) {
    weatherLine += ` (feels like ${feelsLikeC}°C)`;
  }
}

weatherLine += ` — ${capitalise(conditionDesc)}`;

if (weatherType) weatherLine += `, ${weatherType}`;

// ── Details line ──
const detailParts = [];
if (humidity !== null)    detailParts.push(`${humidity}% humidity (${humidityDesc})`);
if (windSpeed !== null)   detailParts.push(`${windDesc}`);
if (visibilityDesc)       detailParts.push(visibilityDesc);
if (cloudPct !== null)    detailParts.push(`${cloudPct}% cloud cover`);

const detailLine = detailParts.length > 0
  ? `\n${detailParts.join(' · ')}`
  : '';

// ── Today's range line ──
const rangeLine = (tempMinC !== null && tempMaxC !== null)
  ? `\nToday's range: ${tempMinC}°C – ${tempMaxC}°C`
  : '';

// ── Sun times line ──
const sunLine = (sunriseTime && sunsetTime)
  ? `\nSunrise ${sunriseTime} · Sunset ${sunsetTime} (local time)`
  : '';

// ── Suggestion line ──
const suggestionLine = suggestion
  ? `\nTip: ${capitalise(suggestion)}.`
  : '';

// ── Bridge back to property search ──
let bridgeLine = '';
if (propertyType && searchCity) {
  bridgeLine = `\n\nWould you like to continue your ${propertyType} search in ${searchCity}?`;
} else if (propertyType) {
  bridgeLine = `\n\nShall I continue searching for ${propertyType}s for you?`;
} else {
  bridgeLine = `\n\nWould you like to search for properties in ${cityName}?`;
}

// ── Assemble full reply ──
const fullReply = weatherLine
  + detailLine
  + rangeLine
  + sunLine
  + suggestionLine
  + bridgeLine;

// ============================================================
// STEP 5 — RETURN
// ============================================================

return [{
  json: {
    action:       'RESPOND',
    updatedState: convState,
    reply:        fullReply,
    _debug: {
      cityName,
      countryCode,
      tempC,
      feelsLikeC,
      tempMinC,
      tempMaxC,
      conditionCode,
      conditionMain,
      conditionDesc,
      weatherType,
      humidity,
      humidityDesc,
      windSpeed,
      windDesc,
      windGust,
      visibilityDesc,
      cloudPct,
      sunriseTime,
      sunsetTime,
      isDay,
      suggestion,
      propertyContextKept: !!propertyType,
      bridgeCity: searchCity || cityName
    }
  }
}];

